BEGIN TRANSACTION;

-- FIX 1 — Devos mislink (item_population_elaborations elab_id=6, A-18 / DEM)
-- The prior evidence_ref_id REF-00571 is Kotloski 2020 ("Genetic Background Influences
-- Acute Response to TBI", 10.3389/fneur.2019.01286) — a TBI-genetics paper mis-cited as
-- "Devos 2019". The real Devos 2019 ("Designing Supportive Soundscapes for Nursing Home
-- Residents with Dementia", 10.3390/ijerph16244904) = REF-00735. Re-point + correct notes.
-- REF-00571 becomes unreferenced after this (it was only used here); the row is left in
-- place (a real paper) and flagged for out-of-scope review in the owner queue.
UPDATE item_population_elaborations
   SET evidence_ref_id = 'REF-00735',
       notes = 'Devos 2019 (REF-00735, Tier 3) cited in BPC. Matches existing BPC language. [corrected 2026-07-18: prior evidence_ref_id REF-00571 was Kotloski 2020 (TBI genetics), a mis-citation of "Devos 2019"; real Devos 2019 = REF-00735.]'
 WHERE elab_id = '6';

-- FIX 2 — ANSI/ASA S12.60-2010 duplicate consolidation onto canonical REF-00563
-- REF-00326/335/604 are duplicate ingestions of the same standard, each linked to a
-- different acoustic slug (DCR-02 / DAB-08 / ASI-04). Canonical = REF-00563 (Part 1 /
-- Schools; the only one carrying the 2 source_value_extractions + the RAP-04 link).
-- Re-point FKs (source_slug_links + spec_value_probes), then mark the dups DUPLICATE-OF
-- (rows retained -> reversible; owner may physically remove in a future migration). ANSI
-- standards carry no DOI, so the DOI-based duplicate integrity check does not flag these;
-- this is a data-quality consolidation, not a CI fix.
UPDATE source_slug_links SET ref_id = 'REF-00563' WHERE ref_id IN ('REF-00326','REF-00335','REF-00604');
UPDATE spec_value_probes  SET ref_id = 'REF-00563' WHERE ref_id = 'REF-00335';
UPDATE evidence_sources
   SET metadata_integrity_status = 'DUPLICATE-OF-REF-00563',
       metadata_integrity_detail = 'ANSI/ASA S12.60-2010 duplicate ingestion consolidated onto canonical REF-00563 (Part 1 / Schools; holds the source_value_extractions). source_slug_links + spec_value_probes FKs re-pointed 2026-07-18. Row retained for forensic history; owner may physically remove in a future migration.',
       verification_note = COALESCE(verification_note,'') || ' | [2026-07-18 evidence-migration dedup] duplicate-of REF-00563; FKs re-pointed',
       updated_at = '2026-07-18T00:00:00Z',
       updated_by_session = 'session_2026-07-18-evidence-migration-issue-resolution'
 WHERE ref_id IN ('REF-00326','REF-00335','REF-00604');

COMMIT;
